int* plusOne(int* d, int n, int* rs) {
    int i;
    for (i = n - 1; i >= 0; i--) {
        if (d[i] < 9) { d[i]++; *rs = n; return d; }
        d[i] = 0;
    }
    int* out = (int*)malloc((n + 1) * sizeof(int));
    out[0] = 1; for (i = 0; i < n; i++) out[i + 1] = 0;
    *rs = n + 1; return out;
}
